func prepareSymlinkTarget(target string, force bool) error {
	if info, err := os.Lstat(target); err == nil {
		if info.Mode()&os.ModeSymlink != 0 || force {
			if err := os.RemoveAll(target); err != nil {
				return fmt.Errorf("removing existing %s: %w", target, err)
			}
			return nil
		}
		return fmt.Errorf("%s already exists (use --force to replace)", target)
	} else if !os.IsNotExist(err) {
		return fmt.Errorf("checking existing %s: %w", target, err)
	}
	return nil
}

// installLocal installs a plugin from a local directory into the current
// checkout as a developer overlay. It intentionally does not update installed
// state and does not auto-commit: the recorded plugin pin remains whatever the
// project already declares, while this machine can test a local plugin tree.
func (f *CommandFactory) installLocal(name, localPath string, force bool, out io.Writer) error {
	// Resolve to absolute path.
	absPath, err := filepath.Abs(localPath)
	if err != nil {
		return fmt.Errorf("resolving path %s: %w", localPath, err)
	}
	if _, err := os.Stat(absPath); os.IsNotExist(err) {
		return fmt.Errorf("local path does not exist: %s", absPath)
	}

	// Load package.yaml when present so local installs honor the manifest
	// contract, but keep the built-in registry as a compatibility fallback.
	reg := registry.BuiltinRegistry()
	fallbackPkg, _ := reg.Find(name)

	pkg, manifestMissing, manifestIssues, manifestErr := registry.LoadPackageManifestWithFallback(absPath, fallbackPkg)
	if manifestErr == nil {
		if strings.TrimSpace(pkg.Name) != "" && pkg.Name != name {
			return fmt.Errorf("local package name %q does not match package.yaml name %q", name, pkg.Name)
		}
	} else {
		if os.IsNotExist(manifestErr) && manifestMissing {
			if pkg == nil {
				pkg = &registry.Package{
					Name:        name,
					Version:     "local",
					Description: "local plugin package",
					Type:        registry.PackageTypePlugin,
					Source:      absPath,
				}
			}
		} else if len(manifestIssues) > 0 {
			return fmt.Errorf("validating package manifest: %w", manifestErr)
		} else {
			return fmt.Errorf("loading package manifest: %w", manifestErr)
		}
	}

	if pkg == nil {
		pkg = &registry.Package{
			Name:        name,
			Version:     "local",
			Description: "local plugin package",
			Type:        registry.PackageTypePlugin,
			Source:      absPath,
		}
	}

	if pkg.Install.Root == nil {
		pkg.Install.Root = &registry.InstallMapping{
			Source: ".",
			Target: fmt.Sprintf(".ddx/plugins/%s", pkg.Name),
		}
	}
	if len(pkg.Install.Skills) == 0 && localPluginHasSkills(absPath) {
		pkg.Install.Skills = []registry.InstallMapping{
			{Source: "skills/", Target: ".agents/skills/"},
		}
	}

	if strings.HasPrefix(pkg.Install.Root.Target, "~") {
		return fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
	}

	projectRoot := f.WorkingDir
	if projectRoot == "" {
		projectRoot, _ = os.Getwd()
	}
	var oldFiles []string
	if state, err := registry.LoadState(); err == nil {
		if old := state.FindInstalled(pkg.Name); old != nil {
			oldFiles = append([]string{}, old.Files...)
			_, _ = markLocalInstallOverlay(projectRoot, pkg.Name, oldFiles)
		}
	}

	if issues := filterLocalInstallValidationIssues(absPath, registry.ValidatePackageStructure(absPath, pkg)); len(issues) > 0 {
		return fmt.Errorf("validating package structure: %s", registry.JoinValidationIssues(issues))
	}

	pluginDir := pkg.Install.Root.Target

	if err := prepareSymlinkTarget(pluginDir, force); err != nil {
		return err
	}

	if err := os.MkdirAll(filepath.Dir(pluginDir), 0755); err != nil {
		return fmt.Errorf("creating plugins dir: %w", err)
	}

	if err := os.Symlink(absPath, pluginDir); err != nil {
		return fmt.Errorf("linking plugin into %s: %w", pluginDir, err)
	}

	fmt.Fprintf(out, "Linked %s -> %s\n", pluginDir, absPath)

	entry := registry.InstalledEntry{
		Name:    pkg.Name,
		Version: pkg.Version,
		Type:    pkg.Type,
		Source:  absPath,
	}
	entry.Files = append(entry.Files, pluginDir)

	// Install local skills as symlinks into each supported harness surface.
	if len(pkg.Install.Skills) > 0 {
		absProject := f.WorkingDir
		if absProject == "" {
			absProject, _ = os.Getwd()
		}
		if !filepath.IsAbs(absProject) {
			absProject, _ = filepath.Abs(absProject)
		}
		writtenSkills, err := installLocalSkillSymlinks(absPath, absProject, force)
		if err != nil {
			return fmt.Errorf("installing skills: %w", err)
		}
		entry.Files = append(entry.Files, writtenSkills...)
	}

	// Copy CLI script if defined (skip if target is a developer symlink).
	if pkg.Install.Scripts != nil {
		dst := registry.ExpandHome(pkg.Install.Scripts.Target)
		if li, lErr := os.Lstat(dst); lErr == nil && li.Mode()&os.ModeSymlink != 0 {
			target, _ := os.Readlink(dst)
			fmt.Fprintf(out, "notice: %s is a symlink → %s (developer mode, skipping copy)\n", dst, target)
			entry.Files = append(entry.Files, dst)
		} else {
			copied, err := registry.CopyScriptFromRoot(pluginDir, pkg.Install.Scripts)
			if err != nil {
				fmt.Fprintf(out, "Warning: script copy error: %v\n", err)
			} else {
				entry.Files = append(entry.Files, copied)
			}
		}
	}

	// Set execute bits on installed plugin files.
	for _, rel := range pkg.Install.Executable {
		p := filepath.Join(pluginDir, filepath.FromSlash(rel))
		if info, err := os.Stat(p); err == nil && !info.IsDir() {
			_ = os.Chmod(p, info.Mode()|0111)
		}
	}

	entry.InstalledAt = time.Now()

	removed := removeStaleFilesFromInstall(oldFiles, entry.Files)
	if removed > 0 {
		fmt.Fprintf(out, "Removed %d stale file(s) from previous install\n", removed)
	}

	if hidden, err := markLocalInstallOverlay(projectRoot, entry.Name, entry.Files); err != nil {
		fmt.Fprintf(out, "Warning: local install is active but git overlay hiding failed: %v\n", err)
	} else if hidden > 0 {
		fmt.Fprintf(out, "Marked %d tracked local overlay file(s) skip-worktree\n", hidden)
	}

	fmt.Fprintf(out, "Installed %s from local path %s — %d file(s); recorded plugin pin unchanged\n", entry.Name, absPath, len(entry.Files))
	return nil
}

func markLocalInstallOverlay(projectRoot, pluginName string, files []string) (int, error) {
	if projectRoot == "" {
		return 0, nil
	}

	ctx := context.Background()
	topOut, err := internalgit.Command(ctx, projectRoot, "rev-parse", "--show-toplevel").Output()
	if err != nil {
		return 0, nil
	}
	repoRoot := strings.TrimSpace(string(topOut))
	if repoRoot == "" {
		return 0, nil
	}

	paths := localOverlayPaths(pluginName, files)
	if len(paths) == 0 {
		return 0, nil
	}
	if err := addLocalOverlayIgnores(repoRoot, paths); err != nil {
		return 0, err
	}

	args := append([]string{"ls-files", "-z", "--"}, paths...)
	trackedOut, err := internalgit.Command(ctx, repoRoot, args...).Output()
	if err != nil {
		return 0, err
	}
	var tracked []string
	for _, p := range strings.Split(string(trackedOut), "\x00") {
		if p != "" {
			tracked = append(tracked, p)
		}
	}
	for start := 0; start < len(tracked); start += 100 {
		end := start + 100
		if end > len(tracked) {
			end = len(tracked)
		}
		args := append([]string{"update-index", "--skip-worktree", "--"}, tracked[start:end]...)
		if err := internalgit.Command(ctx, repoRoot, args...).Run(); err != nil {
			return 0, err
		}
	}
	return len(tracked), nil

	return len(tracked), nil
}

func localPluginHasSkills(root string) bool {
	for _, candidate := range []string{
		filepath.Join(root, ".agents", "skills"),
		filepath.Join(root, "skills"),
	} {
		if info, err := os.Stat(candidate); err == nil && info.IsDir() {
			return true
		}
	}
	return false
}

func localOverlayPaths(pluginName string, files []string) []string {
	seen := map[string]bool{}
	add := func(path string) {
		path = filepath.ToSlash(strings.TrimSpace(path))
		path = strings.TrimPrefix(path, "./")
		if path == "" || strings.HasPrefix(path, "~") || filepath.IsAbs(path) {
			return
		}
		if !seen[path] {
			seen[path] = true
		}
	}

	add(filepath.ToSlash(filepath.Join(".ddx", "plugins", pluginName)))
	for _, file := range files {
		p := filepath.ToSlash(file)
		for _, prefix := range []string{".agents/skills/", ".claude/skills/"} {
			if strings.HasPrefix(p, prefix) {
				rest := strings.TrimPrefix(p, prefix)
				name := strings.Split(rest, "/")[0]
				if name != "" {
					add(prefix + name)
				}
			}
		}
	}

	paths := make([]string, 0, len(seen))
	for p := range seen {
		paths = append(paths, p)
	}
	sort.Strings(paths)
	return paths
}

func installLocalSkillSymlinks(pluginRoot, projectRoot string, force bool) ([]string, error) {
	sourceRoot, entries, err := localSkillSourceEntries(pluginRoot)
	if err != nil {
		return nil, err
	}
	if len(entries) == 0 {
		return nil, nil
	}

	var written []string
	for _, entry := range entries {
		if !entry.IsDir() && entry.Type()&os.ModeSymlink == 0 {
			continue
		}
		name := entry.Name()
		src := filepath.Join(sourceRoot, name)
		if _, err := os.Stat(filepath.Join(src, "SKILL.md")); err != nil {
			return nil, fmt.Errorf("%s: missing SKILL.md: %w", src, err)
		}
		for _, surface := range []string{".agents/skills", ".claude/skills"} {
			dst := filepath.Join(projectRoot, filepath.FromSlash(surface), name)
			if err := prepareSymlinkTarget(dst, force); err != nil {
				return nil, err
			}
			if err := os.MkdirAll(filepath.Dir(dst), 0o755); err != nil {
				return nil, fmt.Errorf("creating skills dir: %w", err)
			}
			target, err := filepath.Rel(filepath.Dir(dst), src)
			if err != nil {
				target = src
			}
			if err := os.Symlink(target, dst); err != nil {
				return nil, fmt.Errorf("linking skill %s -> %s: %w", dst, target, err)
			}
			written = append(written, filepath.Join(filepath.FromSlash(surface), name))
		}
	}
	return written, nil
}

func localSkillSourceEntries(pluginRoot string) (string, []os.DirEntry, error) {
	for _, candidate := range []string{
		filepath.Join(pluginRoot, ".agents", "skills"),
		filepath.Join(pluginRoot, "skills"),
	} {
		entries, err := os.ReadDir(candidate)
		if err == nil && len(entries) > 0 {
			return candidate, entries, nil
		}
		if err != nil && !os.IsNotExist(err) {
			return "", nil, err

			return "", nil, err
		}
	}
	return "", nil, nil
}

func addLocalOverlayIgnores(repoRoot string, paths []string) error {
	excludePath := filepath.Join(repoRoot, ".git", "info", "exclude")
	existing, _ := os.ReadFile(excludePath)
	text := string(existing)

	var additions []string
	for _, p := range paths {
		pattern := filepath.ToSlash(p)
		if !strings.HasSuffix(pattern, "/") {
			pattern += "/"
		}
		if !strings.Contains(text, "\n"+pattern+"\n") && !strings.HasPrefix(text, pattern+"\n") {
			additions = append(additions, pattern)
		}
	}
	if len(additions) == 0 {
		return nil
	}

	var sb strings.Builder
	if len(existing) > 0 && !strings.HasSuffix(text, "\n") {
		sb.WriteString("\n")
	}
	if !strings.Contains(text, "# DDx local plugin overlays") {
		sb.WriteString("\n# DDx local plugin overlays\n")
	}
	for _, pattern := range additions {
		sb.WriteString(pattern)
		sb.WriteString("\n")
	}
	return os.WriteFile(excludePath, append(existing, []byte(sb.String())...), 0o644)
}

// copyDirTree copies the source directory tree into dst as real files,
// returning the list of written file paths (relative to cwd).
func copyDirTree(src, dst string) ([]string, error) {
	var written []string
	err := filepath.Walk(src, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}
		rel, relErr := filepath.Rel(src, path)
		if relErr != nil {
			return relErr
		}
		if shouldSkipLocalInstallPath(rel, info) {
			if info.IsDir() {
				return filepath.SkipDir
			}
			return nil
		}
		target := filepath.Join(dst, rel)
		if info.IsDir() {
			return os.MkdirAll(target, 0o755)
		}

			_ = gitAdd.Run()
		}
	}

	// Check if there's anything to commit.
	status := internalgit.Command(ctx, "", "diff", "--cached", "--quiet")
	if status.Run() == nil {
		return // nothing staged
	}

	msg := fmt.Sprintf("chore: install %s %s", name, version)
	gitCommit := internalgit.Command(ctx, "", "commit", "-m", msg)
	_ = gitCommit.Run()
}

func prepareSymlinkTarget(target string, force bool) error {
	if info, err := os.Lstat(target); err == nil {
		if info.Mode()&os.ModeSymlink != 0 || force {
			if err := os.RemoveAll(target); err != nil {
				return fmt.Errorf("removing existing %s: %w", target, err)
			}
			return nil
		}
		return fmt.Errorf("%s already exists (use --force to replace)", target)
	} else if !os.IsNotExist(err) {
		return fmt.Errorf("checking existing %s: %w", target, err)
	}
	return nil
}

func resolveLocalPackageRoot(absPath string) (string, error) {
	for _, candidate := range []string{
		absPath,
		filepath.Join(absPath, "library"),
	} {
		manifestPath := filepath.Join(candidate, "package.yaml")
		if _, err := os.Stat(manifestPath); err == nil {
			return candidate, nil
		} else if err != nil && !os.IsNotExist(err) {
			return "", fmt.Errorf("checking package manifest %s: %w", manifestPath, err)
		}
	}
	return absPath, nil
}

// installLocal installs a plugin from a local directory into the current
// checkout as a developer overlay. It intentionally does not update installed
// state and does not auto-commit: the recorded plugin pin remains whatever the
// project already declares, while this machine can test a local plugin tree.
func (f *CommandFactory) installLocal(name, localPath string, force bool, out io.Writer) error {
	// Resolve to absolute path.
	absPath, err := filepath.Abs(localPath)
	if err != nil {
		return fmt.Errorf("resolving path %s: %w", localPath, err)
	}
	if _, err := os.Stat(absPath); os.IsNotExist(err) {
		return fmt.Errorf("local path does not exist: %s", absPath)
	}

	// Load package.yaml when present so local installs honor the manifest
	// contract, but keep the built-in registry as a compatibility fallback.
	reg := registry.BuiltinRegistry()
	fallbackPkg, _ := reg.Find(name)

	pkg, manifestMissing, manifestIssues, manifestErr := registry.LoadPackageManifestWithFallback(absPath, fallbackPkg)
	if manifestErr == nil {
		if strings.TrimSpace(pkg.Name) != "" && pkg.Name != name {
			return fmt.Errorf("local package name %q does not match package.yaml name %q", name, pkg.Name)
		}
	} else {
		if os.IsNotExist(manifestErr) && manifestMissing {
			if pkg == nil {
				pkg = &registry.Package{
					Name:        name,
					Version:     "local",
					Description: "local plugin package",
					Type:        registry.PackageTypePlugin,
					Source:      absPath,
				}
			}
		} else if len(manifestIssues) > 0 {
			return fmt.Errorf("validating package manifest: %w", manifestErr)
		} else {
			return fmt.Errorf("loading package manifest: %w", manifestErr)
		}
	}

	if pkg == nil {
		pkg = &registry.Package{
			Name:        name,
			Version:     "local",
			Description: "local plugin package",
			Type:        registry.PackageTypePlugin,
			Source:      absPath,
		}
	}

	localRoot, err := resolveLocalPackageRoot(absPath)
	if err != nil {
		return err
	}

	if pkg.Install.Root == nil {
		pkg.Install.Root = &registry.InstallMapping{
			Source: ".",
			Target: fmt.Sprintf(".ddx/plugins/%s", pkg.Name),
		}
	}

	if strings.HasPrefix(pkg.Install.Root.Target, "~") {
		return fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
	}

	projectRoot := f.WorkingDir
	if projectRoot == "" {
		projectRoot, _ = os.Getwd()
	}
	var oldFiles []string
	if state, err := registry.LoadState(); err == nil {
		if old := state.FindInstalled(pkg.Name); old != nil {
			oldFiles = append([]string{}, old.Files...)
		}
	}

	if issues := filterLocalInstallValidationIssues(localRoot, registry.ValidatePackageStructure(localRoot, pkg)); len(issues) > 0 {
		return fmt.Errorf("validating package structure: %s", registry.JoinValidationIssues(issues))
	}

	pluginDir := pkg.Install.Root.Target

	if err := prepareSymlinkTarget(pluginDir, force); err != nil {
		return err
	}

	if err := os.MkdirAll(filepath.Dir(pluginDir), 0755); err != nil {
		return fmt.Errorf("creating plugins dir: %w", err)
	}

	if err := os.Symlink(localRoot, pluginDir); err != nil {
		return fmt.Errorf("linking plugin into %s: %w", pluginDir, err)
	}

	fmt.Fprintf(out, "Linked %s -> %s\n", pluginDir, localRoot)

	entry := registry.InstalledEntry{
		Name:    pkg.Name,
		Version: pkg.Version,
		Type:    pkg.Type,
		Source:  absPath,
	}
	entry.Files = append(entry.Files, pluginDir)

	// Install local skills as symlinks into each supported harness surface.
	if len(pkg.Install.Skills) > 0 {
		absProject := f.WorkingDir
		if absProject == "" {
			absProject, _ = os.Getwd()
		}
		if !filepath.IsAbs(absProject) {
			absProject, _ = filepath.Abs(absProject)
		}
		writtenSkills, err := installLocalSkillSymlinks(localRoot, absProject, pkg.Install.Skills, force)
		if err != nil {
			return fmt.Errorf("installing skills: %w", err)
		}
		entry.Files = append(entry.Files, writtenSkills...)
	}

	// Copy CLI script if defined (skip if target is a developer symlink).
	if pkg.Install.Scripts != nil {
		dst := registry.ExpandHome(pkg.Install.Scripts.Target)
		if li, lErr := os.Lstat(dst); lErr == nil && li.Mode()&os.ModeSymlink != 0 {
			target, _ := os.Readlink(dst)
			fmt.Fprintf(out, "notice: %s is a symlink → %s (developer mode, skipping copy)\n", dst, target)
			entry.Files = append(entry.Files, dst)
		} else {
			copied, err := registry.CopyScriptFromRoot(pluginDir, pkg.Install.Scripts)
			if err != nil {
				fmt.Fprintf(out, "Warning: script copy error: %v\n", err)
			} else {
				entry.Files = append(entry.Files, copied)
			}
		}
	}

	// Set execute bits on installed plugin files.
	for _, rel := range pkg.Install.Executable {
		p := filepath.Join(pluginDir, filepath.FromSlash(rel))
		if info, err := os.Stat(p); err == nil && !info.IsDir() {
			_ = os.Chmod(p, info.Mode()|0111)
		}
	}

	entry.InstalledAt = time.Now()

	removed := removeStaleFilesFromInstall(oldFiles, entry.Files)
	if removed > 0 {
		fmt.Fprintf(out, "Removed %d stale file(s) from previous install\n", removed)
	}

	if hidden, err := markLocalInstallOverlay(projectRoot, entry.Name, entry.Files); err != nil {
		fmt.Fprintf(out, "Warning: local install is active but git overlay hiding failed: %v\n", err)
	} else if hidden > 0 {
		fmt.Fprintf(out, "Marked %d tracked local overlay file(s) skip-worktree\n", hidden)
	}

	fmt.Fprintf(out, "Installed %s from local path %s — %d file(s); recorded plugin pin unchanged\n", entry.Name, absPath, len(entry.Files))
	return nil
}

func markLocalInstallOverlay(projectRoot, pluginName string, files []string) (int, error) {
	if projectRoot == "" {
		return 0, nil
	}

	ctx := context.Background()
	topOut, err := internalgit.Command(ctx, projectRoot, "rev-parse", "--show-toplevel").Output()
	if err != nil {
		return 0, nil
	}
	repoRoot := strings.TrimSpace(string(topOut))
	if repoRoot == "" {
		return 0, nil
	}

	paths := localOverlayPaths(pluginName, files)
	if len(paths) == 0 {
		return 0, nil
	}
	if err := addLocalOverlayIgnores(repoRoot, paths); err != nil {
		return 0, err
	}

	args := append([]string{"ls-files", "-z", "--"}, paths...)
	trackedOut, err := internalgit.Command(ctx, repoRoot, args...).Output()
	if err != nil {
		return 0, err
	}
	var tracked []string
	for _, p := range strings.Split(string(trackedOut), "\x00") {
		if p != "" {
			tracked = append(tracked, p)
		}
	}
	for start := 0; start < len(tracked); start += 100 {
		end := start + 100
		if end > len(tracked) {
			end = len(tracked)
		}
		args := append([]string{"update-index", "--skip-worktree", "--"}, tracked[start:end]...)
		if err := internalgit.Command(ctx, repoRoot, args...).Run(); err != nil {
			return 0, err
		}
	}
	return len(tracked), nil
}

func localOverlayPaths(pluginName string, files []string) []string {
	seen := map[string]bool{}
	add := func(path string) {
		path = filepath.ToSlash(strings.TrimSpace(path))
		path = strings.TrimPrefix(path, "./")
		if path == "" || strings.HasPrefix(path, "~") || filepath.IsAbs(path) {
			return
		}
		if !seen[path] {
			seen[path] = true
		}
	}

	add(filepath.ToSlash(filepath.Join(".ddx", "plugins", pluginName)))
	for _, file := range files {
		p := filepath.ToSlash(file)
		for _, prefix := range []string{".agents/skills/", ".claude/skills/"} {
			if strings.HasPrefix(p, prefix) {
				rest := strings.TrimPrefix(p, prefix)
				name := strings.Split(rest, "/")[0]
				if name != "" {
					add(prefix + name)
				}
			}
		}
	}

	paths := make([]string, 0, len(seen))
	for p := range seen {
		paths = append(paths, p)
	}
	sort.Strings(paths)
	return paths
}

func installLocalSkillSymlinks(packageRoot, projectRoot string, mappings []registry.InstallMapping, force bool) ([]string, error) {
	var written []string
	for _, mapping := range mappings {
		sourceRoot := filepath.Join(packageRoot, filepath.FromSlash(mapping.Source))
		entries, err := os.ReadDir(sourceRoot)
		if err != nil {
			if os.IsNotExist(err) {
				continue
			}
			return nil, fmt.Errorf("reading skills source %s: %w", sourceRoot, err)
		}
		for _, entry := range entries {
			if !entry.IsDir() {
				continue
			}
			name := entry.Name()
			src := filepath.Join(sourceRoot, name)
			if _, err := os.Stat(filepath.Join(src, "SKILL.md")); err != nil {
				return nil, fmt.Errorf("%s: missing SKILL.md: %w", src, err)
			}
			dst := filepath.Join(projectRoot, filepath.FromSlash(mapping.Target), name)
			if err := prepareSymlinkTarget(dst, force); err != nil {
				return nil, err
			}
			if err := os.MkdirAll(filepath.Dir(dst), 0o755); err != nil {
				return nil, fmt.Errorf("creating skills dir: %w", err)
			}
			target, err := filepath.Rel(filepath.Dir(dst), src)
			if err != nil {
				target = src
			}
			if err := os.Symlink(target, dst); err != nil {
				return nil, fmt.Errorf("linking skill %s -> %s: %w", dst, target, err)
			}
			written = append(written, filepath.Join(filepath.FromSlash(mapping.Target), name))
		}
	}
	return written, nil
}

func addLocalOverlayIgnores(repoRoot string, paths []string) error {
	excludePath := filepath.Join(repoRoot, ".git", "info", "exclude")
	existing, _ := os.ReadFile(excludePath)
	text := string(existing)

	var additions []string
	for _, p := range paths {
		pattern := filepath.ToSlash(p)
		if !strings.HasSuffix(pattern, "/") {

		if !strings.HasSuffix(pattern, "/") {
			pattern += "/"
		}
		if !strings.Contains(text, "\n"+pattern+"\n") && !strings.HasPrefix(text, pattern+"\n") {
			additions = append(additions, pattern)
		}
	}
	if len(additions) == 0 {
		return nil
	}

	var sb strings.Builder
	if len(existing) > 0 && !strings.HasSuffix(text, "\n") {
		sb.WriteString("\n")
	}
	if !strings.Contains(text, "# DDx local plugin overlays") {
		sb.WriteString("\n# DDx local plugin overlays\n")
	}
	for _, pattern := range additions {
		sb.WriteString(pattern)
		sb.WriteString("\n")
	}
	return os.WriteFile(excludePath, append(existing, []byte(sb.String())...), 0o644)
}

// copyDirTree copies the source directory tree into dst as real files,
// returning the list of written file paths (relative to cwd).
func copyDirTree(src, dst string) ([]string, error) {
	var written []string
	err := filepath.Walk(src, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}
		rel, relErr := filepath.Rel(src, path)
		if relErr != nil {
			return relErr
		}
		if shouldSkipLocalInstallPath(rel, info) {
			if info.IsDir() {
				return filepath.SkipDir
			}
			return nil
		}
		target := filepath.Join(dst, rel)
		if info.IsDir() {
			return os.MkdirAll(target, 0o755)
		}
		if info.Mode()&os.ModeSymlink != 0 {
			// Skip plugin-source symlinks — never materialize.
			return nil
		}
		if !info.Mode().IsRegular() {
			return nil
		}
		if err := os.MkdirAll(filepath.Dir(target), 0o755); err != nil {
			return err
		}
		in, err := os.Open(path)
		if err != nil {
			return err
		}
		defer func() { _ = in.Close() }()
		out, err := os.OpenFile(target, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, info.Mode())
		if err != nil {
			return err
		}
		if _, copyErr := io.Copy(out, in); copyErr != nil {
			_ = out.Close()
			return copyErr
		}
		if err := out.Close(); err != nil {
			return err
		}
		written = append(written, target)
		return nil
	})
	return written, err
}

func filterLocalInstallValidationIssues(root string, issues []registry.ValidationIssue) []registry.ValidationIssue {
	filtered := issues[:0]

package git

import (
	"context"
	"fmt"
	"os"
	"os/exec"
	"strings"
	"sync"
)

// Command returns a prepared *exec.Cmd for a git invocation that honors
// cmd.Dir / -C <path> rather than whatever GIT_DIR / GIT_WORK_TREE / etc.
// were set in the parent environment.
//
// Why this wrapper exists (ddx-aa8a5fb3):
// Git's repository-discovery rules mean that if GIT_DIR is set in the
// process environment, git uses THAT repo and ignores both -C <path> and
// the process's working directory for repository selection. ddx commands
// invoked from a git hook (lefthook pre-commit, pre-push, etc.) inherit
// the hook's GIT_DIR / GIT_WORK_TREE / GIT_INDEX_FILE. Without stripping
// those, any exec.Command("git", ...) inside ddx mutates the hook's
// repository (the outer one), producing core.bare=true flips and stray
// core.worktree entries in .git/config.
//
// The wrapper strips exactly git's "local env vars" set (the vars git
// itself clears when spawning worktree subprocesses). This is the
// canonical set documented by `git rev-parse --local-env-vars`. It
// preserves everything else, including GIT_SSH_COMMAND, GIT_TRACE*,
// GIT_AUTHOR/COMMITTER_NAME/EMAIL, and custom debugging overrides.
//
// Dir must be an absolute or working-directory-relative path; it is set
// on the returned cmd so that when no GIT_* local vars are in the
// environment, git discovers the repo from Dir.
func Command(ctx context.Context, dir string, args ...string) *exec.Cmd {
	warnOnce.Do(maybeWarnGitDirLeaked)

	cmd := exec.CommandContext(ctx, "git", args...)
	if dir != "" {
		cmd.Dir = dir
	}
	cmd.Env = CleanEnv()
	return cmd
}

// CleanEnv returns os.Environ() with every git local-env-var removed.
// Exported so sibling packages (e.g. internal/agent) that spawn NON-git
// subprocesses inside a worktree can use the same scrub — those child
// processes often invoke git themselves and need the same protection.
func CleanEnv() []string {
	vars := localEnvVars()
	src := os.Environ()
	out := make([]string, 0, len(src))
	for _, kv := range src {
		eq := strings.IndexByte(kv, '=')
		if eq < 0 {
			out = append(out, kv)
			continue
		}
		if vars[kv[:eq]] {
			continue
		}
		out = append(out, kv)
	}
	return out
}

// localEnvVars returns the set of environment variable names that git
// treats as repository-local (i.e. scoped to the current git process's
// repository selection and cleared when git itself spawns subprocesses
// for other worktrees). Result is cached for process lifetime.
//
// We query `git rev-parse --local-env-vars` once at first use so we pick
// up any vars a newer git version adds. If that query fails (git not on
// PATH, or restricted environment), fall back to the documented set.
func localEnvVars() map[string]bool {
	localEnvVarsOnce.Do(func() {
		set := map[string]bool{}
		// Use exec.Command directly here to avoid recursion through
		// Command(). This runs with inherited env on purpose: even if
		// GIT_DIR is set, `git rev-parse --local-env-vars` is a static
		// list of variable NAMES (not their values), so inherited env
		// doesn't affect the output.
		out, err := exec.Command("git", "rev-parse", "--local-env-vars").Output()
		if err == nil {
			for _, name := range strings.Fields(string(out)) {
				if name != "" {
					set[name] = true
				}
			}
		}
		// Fallback / supplement: the canonical set from git's source
		// (environment.c local_repo_env[]). Kept inline so ddx remains
		// functional even if `git rev-parse` is unavailable.
		for _, name := range []string{
			"GIT_DIR",
			"GIT_WORK_TREE",
			"GIT_INDEX_FILE",
			"GIT_COMMON_DIR",
			"GIT_OBJECT_DIRECTORY",
			"GIT_ALTERNATE_OBJECT_DIRECTORIES",
			"GIT_PREFIX",
			"GIT_INTERNAL_GETTEXT_SH_SCHEME",
			"GIT_SHALLOW_FILE",
			"GIT_NO_REPLACE_OBJECTS",
			"GIT_REPLACE_REF_BASE",
			"GIT_CONFIG",
			"GIT_CONFIG_GLOBAL",
			"GIT_CONFIG_SYSTEM",
			"GIT_CONFIG_PARAMETERS",
			"GIT_CONFIG_COUNT",
			"GIT_INDEX_VERSION",
			"GIT_LITERAL_PATHSPECS",
			"GIT_GLOB_PATHSPECS",
			"GIT_NOGLOB_PATHSPECS",
			"GIT_ICASE_PATHSPECS",
			"GIT_QUARANTINE_PATH",
			"GIT_INTERNAL_NEW_OBJECT_HOOK",
			"GIT_IMPLICIT_WORK_TREE",
		} {

func ValidatePackageStructure(root string, pkg *Package) []ValidationIssue {
	if pkg == nil {
		return []ValidationIssue{{Path: filepath.Join(root, "package.yaml"), Message: "missing package definition"}}
	}
	return auditPluginRoot(root, pkg)
}

func loadPackageDefinitionForAudit(root string, fallback *Package) (*Package, bool, []ValidationIssue) {
	manifest, manifestMissing, issues, err := LoadPackageManifestWithFallback(root, fallback)
	if err == nil || os.IsNotExist(err) {
		// Report validation issues even when package is valid, so audit shows schema problems.
		return manifest, manifestMissing, issues
	}

	// If a partial package was returned (YAML parsed but validation issues exist),
	// return it with the issues so structural audits can proceed.
	if manifest != nil {
		return manifest, false, issues
	}

	if len(issues) == 0 {
		issues = append(issues, ValidationIssue{Path: filepath.Join(root, "package.yaml"), Message: err.Error()})
	}
	return manifest, false, issues
}

func auditPluginRoot(root string, pkg *Package) []ValidationIssue {
	var issues []ValidationIssue

	if pkg.APIVersion != "" && pkg.APIVersion != SupportedPackageAPIVersion {
		issues = append(issues, ValidationIssue{
			Path:    filepath.Join(root, "package.yaml"),
			Message: fmt.Sprintf("unsupported `api_version` %q (supported: %s)", pkg.APIVersion, SupportedPackageAPIVersion),
		})
	}

	ignoredBrokenSymlinkPaths := collectIgnoredBrokenSymlinkPaths(root, pkg)
	for _, symlinkIssue := range auditBrokenSymlinks(root, ignoredBrokenSymlinkPaths) {
		issues = append(issues, symlinkIssue)
	}

	for _, skillRoot := range collectSkillRoots(root, pkg) {
		issues = append(issues, auditSkillRoot(root, skillRoot)...)
	}

	for _, rel := range pkg.Install.Executable {
		issues = append(issues, auditExecutable(root, rel)...)
	}

	return issues
}

func auditRecordedFiles(entry InstalledEntry) []ValidationIssue {
	var issues []ValidationIssue
	seen := map[string]bool{}
	recordedPaths := append([]string(nil), entry.Files...)
	if root := installedRootPath(entry); root != "" {
		recordedPaths = append(recordedPaths, root)
	}
	for _, recorded := range recordedPaths {
		path := ExpandHome(recorded)
		if path == "" || seen[path] {
			continue
		}
		seen[path] = true
		info, err := os.Lstat(path)
		if err != nil {
			if os.IsNotExist(err) {
				// Pre-migration entries whose paths begin with ~ are outside the
				// project root; treat missing paths as no-op (no issue raised).
				if strings.HasPrefix(recorded, "~") {
					continue
				}
				issues = append(issues, ValidationIssue{Path: path, Message: "missing recorded file or symlink"})
				continue
			}
			issues = append(issues, ValidationIssue{Path: path, Message: err.Error()})
			continue
		}
		if info.Mode()&os.ModeSymlink == 0 {
			continue
		}

		target, err := os.Readlink(path)
		if err != nil {
			issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink: %v", err)})
			continue
		}
		if !filepath.IsAbs(target) {
			target = filepath.Join(filepath.Dir(path), target)
		}
		if _, err := os.Stat(target); err != nil {
			issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink target %q: %v", target, err)})
		}
	}
	return issues
}

func auditBrokenSymlinks(root string, ignored map[string]bool) []ValidationIssue {
	var issues []ValidationIssue
	walkRoot := root
	if resolved, err := filepath.EvalSymlinks(root); err == nil && resolved != "" {
		walkRoot = resolved
	}

	_ = filepath.WalkDir(walkRoot, func(path string, d fs.DirEntry, err error) error {
		if err != nil {
			issues = append(issues, ValidationIssue{Path: path, Message: err.Error()})
			return nil
		}
		if path == walkRoot {
			return nil
		}

		info, err := os.Lstat(path)
		if err != nil {
			if os.IsNotExist(err) {
				issues = append(issues, ValidationIssue{Path: path, Message: "missing installed file"})
				return nil
			}
			issues = append(issues, ValidationIssue{Path: path, Message: err.Error()})
			return nil
		}
		if info.Mode()&os.ModeSymlink == 0 {
			return nil
		}
		if ignored != nil && ignored[path] {
			return nil
		}

		target, err := os.Readlink(path)
		if err != nil {
			issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink: %v", err)})
			return nil
		}
		if !filepath.IsAbs(target) {
			target = filepath.Join(filepath.Dir(path), target)
		}
		if _, err := os.Stat(target); err != nil {
			issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink target %q: %v", target, err)})
		}
		return nil
	})

	return issues
}

func collectSkillRoots(root string, pkg *Package) []string {
	seen := map[string]bool{}
	var roots []string

	add := func(candidate string) {
		if strings.TrimSpace(candidate) == "" {
			return
		}
		abs := candidate
		if resolved, err := filepath.EvalSymlinks(candidate); err == nil && resolved != "" {
			abs = resolved
		} else if resolved, err := filepath.Abs(candidate); err == nil && resolved != "" {
			abs = resolved
		}
		if seen[abs] {
			return
		}
		if _, err := os.Stat(candidate); err != nil {
			return
		}
		seen[abs] = true
		roots = append(roots, candidate)
	}

	for _, mapping := range pkg.Install.Skills {
		sourceRoot := filepath.Join(root, filepath.FromSlash(mapping.Source))
		add(sourceRoot)

		cleanSource := filepath.Clean(filepath.FromSlash(mapping.Source))
		switch cleanSource {
		case filepath.Join(".agents", "skills"), filepath.Join(".claude", "skills"):
			add(filepath.Join(root, "skills"))
		}
	}

	return roots
}

func collectIgnoredBrokenSymlinkPaths(root string, pkg *Package) map[string]bool {
	ignored := make(map[string]bool)
	for _, mapping := range pkg.Install.Skills {
		cleanSource := filepath.Clean(filepath.FromSlash(mapping.Source))
		switch cleanSource {
		case filepath.Join(".agents", "skills"), filepath.Join(".claude", "skills"):
			skillRoot := filepath.Join(root, cleanSource)
			entries, err := os.ReadDir(skillRoot)
			if err != nil {
				continue
			}
			for _, entry := range entries {
				ignored[filepath.Join(skillRoot, entry.Name())] = true
			}
		}
	}
	return ignored
}

func auditSkillRoot(packageRoot, root string) []ValidationIssue {
	var issues []ValidationIssue

	info, err := os.Stat(root)
	if err != nil {
		issues = append(issues, ValidationIssue{Path: root, Message: err.Error()})
		return issues
	}
	if !info.IsDir() {
		issues = append(issues, ValidationIssue{Path: root, Message: "expected a skill directory"})
		return issues
	}

	entries, err := os.ReadDir(root)
	if err != nil {
		issues = append(issues, ValidationIssue{Path: root, Message: err.Error()})
		return issues
	}

	for _, entry := range entries {
		skillPath := filepath.Join(root, entry.Name())
		skillInfo, err := os.Lstat(skillPath)
		if err != nil {
			issues = append(issues, ValidationIssue{Path: skillPath, Message: err.Error()})
			continue
		}
		if skillInfo.Mode()&os.ModeSymlink != 0 {
			if _, err := os.Stat(skillPath); err != nil {
				if recovered := recoverSkillDir(packageRoot, root, entry.Name()); recovered != "" {
					skillPath = recovered
				} else {
					issues = append(issues, ValidationIssue{Path: skillPath, Message: fmt.Sprintf("broken symlink: %v", err)})
					continue
				}
			}
		}
		if !skillInfo.IsDir() && skillInfo.Mode()&os.ModeSymlink == 0 {
			continue
		}

		skillFile := filepath.Join(skillPath, "SKILL.md")
		data, err := os.ReadFile(skillFile)
		if err != nil {
			if os.IsNotExist(err) {
				issues = append(issues, ValidationIssue{Path: skillPath, Message: "missing SKILL.md"})
				continue
			}
			issues = append(issues, ValidationIssue{Path: skillFile, Message: err.Error()})
			continue
		}

		for _, issue := range skills.ValidateContent(skillFile, data) {
			issues = append(issues, ValidationIssue{Path: issue.Path, Message: issue.Message})
		}
	}

	return issues
}

func recoverSkillDir(packageRoot, skillRoot, skillName string) string {
	candidate := filepath.Join(packageRoot, "skills", skillName)
	if info, err := os.Stat(candidate); err == nil && info.IsDir() {
		return candidate
	}

	if strings.HasSuffix(filepath.Clean(skillRoot), filepath.Join(".agents", "skills")) ||
		strings.HasSuffix(filepath.Clean(skillRoot), filepath.Join(".claude", "skills")) {
		candidate = filepath.Join(packageRoot, "skills", skillName)
		if info, err := os.Stat(candidate); err == nil && info.IsDir() {
			return candidate
		}
	}

	return ""
}

func auditExecutable(root, rel string) []ValidationIssue {
	path := filepath.Join(root, filepath.FromSlash(rel))
	info, err := os.Stat(path)
	if err != nil {
		return []ValidationIssue{{Path: path, Message: err.Error()}}
	}
	if info.IsDir() {
		return []ValidationIssue{{Path: path, Message: "expected executable file, found directory"}}
	}
	if info.Mode()&0111 == 0 {
		return []ValidationIssue{{Path: path, Message: "file lost execute permission"}}
	}
	return nil
}

func installedRootPath(entry InstalledEntry) string {
	resolve := func(raw string) string {

	files, err := copyMapping(installedRoot, mapping)
	if err != nil {
		return "", err
	}
	dst := ExpandHome(mapping.Target)
	if info, err := os.Stat(dst); err == nil && !info.IsDir() {
		_ = os.Chmod(dst, info.Mode()|0111)
	}
	if len(files) > 0 {
		return files[0], nil
	}
	return dst, nil
}

// copyMapping copies files from srcDir/<mapping.Source> to ExpandHome(mapping.Target).
// If the source is a single file and the target does not end with a path
// separator, the target is treated as the exact destination file path.
// If the source is a directory (or target ends with /), files are copied
// into the target directory.
// Returns the list of destination files written.
func copyMapping(srcDir string, mapping *InstallMapping) ([]string, error) {
	src := filepath.Join(srcDir, filepath.FromSlash(mapping.Source))
	dst := ExpandHome(mapping.Target)

	info, err := os.Stat(src)
	if os.IsNotExist(err) {
		// Source path doesn't exist in this repo — skip silently.
		return nil, nil
	}
	if err != nil {
		return nil, err
	}

	var written []string

	if info.IsDir() {
		// If dst is an existing symlink (e.g. from a prior --local install),
		// remove it before creating the real directory.
		if li, err := os.Lstat(dst); err == nil && li.Mode()&os.ModeSymlink != 0 {
			if err := os.Remove(dst); err != nil {
				return nil, fmt.Errorf("removing symlink at %s: %w", dst, err)
			}
		}

		// Copy directory tree into dst (create dst as a directory).
		if err := os.MkdirAll(dst, 0755); err != nil {
			return nil, fmt.Errorf("creating target dir %s: %w", dst, err)
		}

		// HELIX skills use symlinks, so resolve each entry via os.Stat.
		entries, err := os.ReadDir(src)
		if err != nil {
			return nil, err
		}
		for _, e := range entries {
			srcPath := filepath.Join(src, e.Name())
			dstPath := filepath.Join(dst, e.Name())

			fi, err := os.Stat(srcPath)
			if err != nil {
				continue // skip broken symlinks
			}

			if fi.IsDir() {
				subFiles, subErr := copyMapping(srcPath, &InstallMapping{Source: ".", Target: dstPath})
				if subErr != nil {
					return nil, subErr
				}
				written = append(written, subFiles...)
			} else if fi.Mode().IsRegular() {
				if err := copyFile(srcPath, dstPath); err != nil {
					return nil, err
				}
				written = append(written, dstPath)
			}
		}
	} else {
		// Source is a single file. If target ends with /, copy into that
		// directory using the source filename; otherwise treat target as
		// the exact destination file path.
		var dstFile string
		if strings.HasSuffix(mapping.Target, "/") {
			if err := os.MkdirAll(dst, 0755); err != nil {
				return nil, fmt.Errorf("creating target dir %s: %w", dst, err)
			}
			dstFile = filepath.Join(dst, filepath.Base(src))
		} else {
			dstFile = dst
		}
		if err := copyFile(src, dstFile); err != nil {
			return nil, err

